import { Component, Input } from '@angular/core';

@Component({
  selector: 'app-score-card',
  templateUrl: './score-card.component.html'
})
export class ScoreCardComponent {
  @Input() title = 'ATS Score';
  @Input() score = 0;

  get tone(): string {
    if (this.score >= 80) {
      return 'text-pine';
    }
    if (this.score >= 60) {
      return 'text-brass';
    }
    return 'text-poppy';
  }
}
<div class="glass-panel p-6">
  <p class="text-sm font-semibold uppercase tracking-[0.28em] text-ink/45">{{ title }}</p>
  <div class="mt-5 flex items-end justify-between">
    <div>
      <p class="section-title text-5xl" [ngClass]="tone">{{ score }}</p>
      <p class="mt-2 text-sm text-ink/60">Out of 100</p>
    </div>
    <div class="h-16 w-16 rounded-full border-8 border-ink/10" [ngClass]="{
      'border-t-pine': score >= 80,
      'border-t-brass': score >= 60 && score < 80,
      'border-t-poppy': score < 60
    }"></div>
  </div>
</div>
